    |> assign(:session, session)
    |> assign(:session_config, config)
    |> register_before_send(&write_session_cookie/1)
  end

  defp write_session_cookie(conn) do
    case conn.assigns[:session_to_write] do
      nil ->
        conn

      session_data ->
        config = conn.assigns[:session_config]
        cookie_value = SessionManager.create_session(session_data)
        put_resp_cookie(conn, config.cookie_name, cookie_value, config.cookie_opts)
    end
